/* Create shapes using clip-path:
   - Hexagon: use polygon() for a 6-sided shape
   - Circle clip: use circle() to clip to a circle
   - Arrow: use polygon() for a right-pointing arrow
   Each shape: 120x120px, centered text, colored background */
.shapes {
  display: flex;
  gap: 32px;
  padding: 20px;
  align-items: center;
  justify-content: center;
}
.shape {
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: bold;
  font-size: 14px;
}

